static void sched_avg_update(struct rq *rq)
{
	s64 period = sched_avg_period();
	while ((s64)(rq->clock - rq->age_stamp) > period) {
		asm("" : "+rm" (rq->age_stamp));
		rq->age_stamp += period;
		rq->rt_avg /= 2;
	}
}

