static void CachedArrayAttributeAttributeGetter(const v8::FunctionCallbackInfo<v8::Value>& info) {
  v8::Local<v8::Object> holder = info.Holder();
  TestObject* impl = V8TestObject::ToImpl(holder);
  V8PrivateProperty::Symbol property_symbol =
      V8PrivateProperty::GetSymbol(info.GetIsolate(),
          kPrivatePropertyCachedArrayAttribute);
  if (!static_cast<const TestObject*>(impl)->isFrozenArrayDirty()) {
    v8::Local<v8::Value> v8_value;
    if (property_symbol.GetOrUndefined(holder).ToLocal(&v8_value) && !v8_value->IsUndefined()) {
      V8SetReturnValue(info, v8_value);
      return;
    }
  }
  Vector<String> cpp_value(impl->cachedArrayAttribute());
  v8::Local<v8::Value> v8_value(FreezeV8Object(ToV8(cpp_value, holder, info.GetIsolate()), info.GetIsolate()));
  property_symbol.Set(holder, v8_value);
  V8SetReturnValue(info, v8_value);
}

bool Vp9Parser::ParseSuperframe() {
  const uint8_t* stream = stream_;
  off_t bytes_left = bytes_left_;
  DCHECK(frames_.empty());
  stream_ = nullptr;
  bytes_left_ = 0;
  if (bytes_left < 1)
    return false;
  uint8_t marker = *(stream + bytes_left - 1);
  if ((marker & 0xe0) != 0xc0) {
    frames_.push_back(FrameInfo(stream, bytes_left));
    return true;
  }
  DVLOG(1) << "Parsing a superframe";
  size_t num_frames = (marker & 0x7) + 1;
  size_t mag = ((marker >> 3) & 0x3) + 1;
  off_t index_size = 2 + mag * num_frames;
  if (bytes_left < index_size)
     return false;
  const uint8_t* index_ptr = stream + bytes_left - index_size;
  if (marker != *index_ptr)
    return false;
  ++index_ptr;
  bytes_left -= index_size;
  for (size_t i = 0; i < num_frames; ++i) {
    uint32_t size = 0;
    for (size_t j = 0; j < mag; ++j) {
      size |= *index_ptr << (j * 8);
      ++index_ptr;
    }
    if (base::checked_cast<off_t>(size) > bytes_left) {
      DVLOG(1) << "Not enough data in the buffer for frame " << i;
      return false;
    }
    frames_.push_back(FrameInfo(stream, size));
    stream += size;
    bytes_left -= size;
    DVLOG(1) << "Frame " << i << ", size: " << size;
  }
   return true;
 }

PermissionsData::PageAccess PermissionsData::CanRunOnPage(
    const GURL& document_url,
    int tab_id,
    const URLPatternSet& permitted_url_patterns,
    const URLPatternSet& withheld_url_patterns,
    const URLPatternSet* tab_url_patterns,
    std::string* error) const {
  runtime_lock_.AssertAcquired();
  if (location_ != Manifest::COMPONENT &&
      IsPolicyBlockedHostUnsafe(document_url)) {
    if (error)
    return PageAccess::kDenied;
  }
  if (IsRestrictedUrl(document_url, error))
    return PageAccess::kDenied;
  if (tab_url_patterns && tab_url_patterns->MatchesURL(document_url))
    return PageAccess::kAllowed;
  if (permitted_url_patterns.MatchesURL(document_url))
    return PageAccess::kAllowed;
  if (withheld_url_patterns.MatchesURL(document_url))
    return PageAccess::kWithheld;
  if (error) {
    if (active_permissions_unsafe_->HasAPIPermission(APIPermission::kTab)) {
          manifest_errors::kCannotAccessPageWithUrl, document_url.spec());
    } else {
    }
  }
  return PageAccess::kDenied;
}

