	fci.retval_ptr_ptr = &retval_ptr;
	if (zend_call_function(&fci, &fci_cache TSRMLS_CC) == SUCCESS && fci.retval_ptr_ptr && *fci.retval_ptr_ptr) {
		COPY_PZVAL_TO_ZVAL(*return_value, *fci.retval_ptr_ptr);
	}
	if (fci.params) {
		efree(fci.params);
	}
}

