 jbig2_image_compose(Jbig2Ctx *ctx, Jbig2Image *dst, Jbig2Image *src, int x, int y, Jbig2ComposeOp op)
 {
    int i, j;
    int w, h;
    int leftbyte, rightbyte;
    int shift;
     uint8_t *s, *ss;
     uint8_t *d, *dd;
     uint8_t mask, rightmask;
    if (op != JBIG2_COMPOSE_OR) {
        return jbig2_image_compose_unopt(ctx, dst, src, x, y, op);
    }
    w = src->width;
    h = src->height;
    ss = src->data;
    if (x < 0) {
        w += x;
        x = 0;
    }
    if (y < 0) {
         h += y;
         y = 0;
     }
    w = (x + w < dst->width) ? w : dst->width - x;
    h = (y + h < dst->height) ? h : dst->height - y;
 #ifdef JBIG2_DEBUG
     jbig2_error(ctx, JBIG2_SEVERITY_DEBUG, -1, "compositing %dx%d at (%d, %d) after clipping\n", w, h, x, y);
 #endif
    if ((w <= 0) || (h <= 0)) {
#ifdef JBIG2_DEBUG
        jbig2_error(ctx, JBIG2_SEVERITY_DEBUG, -1, "zero clipping region");
#endif
        return 0;
    }
#if 0
       buffer is all-blank. */
    if ((x == 0) && (w == src->width)) {
        memcpy(dst->data + y * dst->stride, src->data, h * src->stride);
        return 0;
     }
 #endif
    leftbyte = x >> 3;
    rightbyte = (x + w - 1) >> 3;
     shift = x & 7;
    s = ss;
    d = dd = dst->data + y * dst->stride + leftbyte;
    if (d < dst->data || leftbyte > dst->stride || h * dst->stride < 0 || d - leftbyte + h * dst->stride > dst->data + dst->height * dst->stride) {
        return jbig2_error(ctx, JBIG2_SEVERITY_FATAL, -1, "preventing heap overflow in jbig2_image_compose");
    }
    if (leftbyte == rightbyte) {
        mask = 0x100 - (0x100 >> w);
        for (j = 0; j < h; j++) {
            d += dst->stride;
            s += src->stride;
        }
    } else if (shift == 0) {
        rightmask = (w & 7) ? 0x100 - (1 << (8 - (w & 7))) : 0xFF;
        for (j = 0; j < h; j++) {
            for (i = leftbyte; i < rightbyte; i++)
            d = (dd += dst->stride);
            s = (ss += src->stride);
        }
    } else {
        bool overlap = (((w + 7) >> 3) < ((x + w + 7) >> 3) - (x >> 3));
        mask = 0x100 - (1 << shift);
        if (overlap)
            rightmask = (0x100 - (0x100 >> ((x + w) & 7))) >> (8 - shift);
        else
            rightmask = 0x100 - (0x100 >> (w & 7));
        for (j = 0; j < h; j++) {
            for (i = leftbyte; i < rightbyte - 1; i++) {
            }
            if (overlap)
            else
            d = (dd += dst->stride);
            s = (ss += src->stride);
        }
    }
    return 0;
}

long Cluster::Parse(long long& pos, long& len) const {
 long status = Load(pos, len);
 if (status < 0)
 return status;
  assert(m_pos >= m_element_start);
  assert(m_timecode >= 0);
 const long long cluster_stop =
 (m_element_size < 0) ? -1 : m_element_start + m_element_size;
 if ((cluster_stop >= 0) && (m_pos >= cluster_stop))
 return 1; // nothing else to do
 IMkvReader* const pReader = m_pSegment->m_pReader;
 long long total, avail;
  status = pReader->Length(&total, &avail);
 if (status < 0) // error
 return status;
  assert((total < 0) || (avail <= total));
  pos = m_pos;
 for (;;) {
 if ((cluster_stop >= 0) && (pos >= cluster_stop))
 break;
 if ((total >= 0) && (pos >= total)) {
 if (m_element_size < 0)
        m_element_size = pos - m_element_start;
 break;
 }
 if ((pos + 1) > avail) {
      len = 1;
 return E_BUFFER_NOT_FULL;
 }
 long long result = GetUIntLength(pReader, pos, len);
 if (result < 0) // error
 return static_cast<long>(result);
 if (result > 0) // weird
 return E_BUFFER_NOT_FULL;
 if ((cluster_stop >= 0) && ((pos + len) > cluster_stop))
 return E_FILE_FORMAT_INVALID;
 if ((pos + len) > avail)
 return E_BUFFER_NOT_FULL;
 const long long id = ReadUInt(pReader, pos, len);
 if (id < 0) // error
 return static_cast<long>(id);
 if (id == 0) // weird
 return E_FILE_FORMAT_INVALID;
 if ((id == 0x0F43B675) || (id == 0x0C53BB6B)) { // Cluster or Cues ID
 if (m_element_size < 0)
        m_element_size = pos - m_element_start;
 break;
 }
    pos += len; // consume ID field
 if ((pos + 1) > avail) {
      len = 1;
 return E_BUFFER_NOT_FULL;
 }
    result = GetUIntLength(pReader, pos, len);
 if (result < 0) // error
 return static_cast<long>(result);
 if (result > 0) // weird
 return E_BUFFER_NOT_FULL;
 if ((cluster_stop >= 0) && ((pos + len) > cluster_stop))
 return E_FILE_FORMAT_INVALID;
 if ((pos + len) > avail)
 return E_BUFFER_NOT_FULL;
 const long long size = ReadUInt(pReader, pos, len);
 if (size < 0) // error
 return static_cast<long>(size);
 const long long unknown_size = (1LL << (7 * len)) - 1;
 if (size == unknown_size)
 return E_FILE_FORMAT_INVALID;
    pos += len; // consume size field
 if ((cluster_stop >= 0) && (pos > cluster_stop))
 return E_FILE_FORMAT_INVALID;
 if (size == 0) // weird
 continue;
 const long long block_stop = pos + size;
 if (cluster_stop >= 0) {
 if (block_stop > cluster_stop) {
 if ((id == 0x20) || (id == 0x23))
 return E_FILE_FORMAT_INVALID;
        pos = cluster_stop;
 break;
 }
 } else if ((total >= 0) && (block_stop > total)) {
      m_element_size = total - m_element_start;
      pos = total;
 break;
 } else if (block_stop > avail) {
      len = static_cast<long>(size);
 return E_BUFFER_NOT_FULL;
 }
 Cluster* const this_ = const_cast<Cluster*>(this);
 if (id == 0x20) // BlockGroup
 return this_->ParseBlockGroup(size, pos, len);
 if (id == 0x23) // SimpleBlock
       return this_->ParseSimpleBlock(size, pos, len);
     pos += size;  // consume payload
    assert((cluster_stop < 0) || (pos <= cluster_stop));
   }
   assert(m_element_size > 0);
   m_pos = pos;
  assert((cluster_stop < 0) || (m_pos <= cluster_stop));
   if (m_entries_count > 0) {
     const long idx = m_entries_count - 1;
 const BlockEntry* const pLast = m_entries[idx];
    assert(pLast);
 const Block* const pBlock = pLast->GetBlock();
    assert(pBlock);
 const long long start = pBlock->m_start;
 if ((total >= 0) && (start > total))
 return -1; // defend against trucated stream
 const long long size = pBlock->m_size;
 const long long stop = start + size;
    assert((cluster_stop < 0) || (stop <= cluster_stop));
 if ((total >= 0) && (stop > total))
 return -1; // defend against trucated stream
 }
 return 1; // no more entries
}

void ide_exec_cmd(IDEBus *bus, uint32_t val)
{
    IDEState *s;
    bool complete;
#if defined(DEBUG_IDE)
    printf("ide: CMD=%02x\n", val);
#endif
    s = idebus_active_if(bus);
    if (s != bus->ifs && !s->blk) {
        return;
    }
    if ((s->status & (BUSY_STAT|DRQ_STAT)) && val != WIN_DEVICE_RESET)
        return;
    if (!ide_cmd_permitted(s, val)) {
        ide_abort_command(s);
        ide_set_irq(s->bus);
        return;
    }
    s->status = READY_STAT | BUSY_STAT;
    s->error = 0;
    s->io_buffer_offset = 0;
    complete = ide_cmd_table[val].handler(s, val);
    if (complete) {
        s->status &= ~BUSY_STAT;
        assert(!!s->error == !!(s->status & ERR_STAT));
        if ((ide_cmd_table[val].flags & SET_DSC) && !s->error) {
            s->status |= SEEK_STAT;
        }
        ide_cmd_done(s);
        ide_set_irq(s->bus);
    }
}

IMPEG2D_ERROR_CODES_T impeg2d_dec_seq_hdr(dec_state_t *ps_dec)
{
 stream_t *ps_stream;
    ps_stream = &ps_dec->s_bit_stream;
    UWORD16 u2_height;
    UWORD16 u2_width;
 if (impeg2d_bit_stream_nxt(ps_stream,START_CODE_LEN) != SEQUENCE_HEADER_CODE)
 {
        impeg2d_bit_stream_flush(ps_stream,START_CODE_LEN);
 return IMPEG2D_FRM_HDR_START_CODE_NOT_FOUND;
 }
    impeg2d_bit_stream_flush(ps_stream,START_CODE_LEN);
    u2_width    = impeg2d_bit_stream_get(ps_stream,12);
    u2_height   = impeg2d_bit_stream_get(ps_stream,12);
 if (0 == u2_width || 0 == u2_height)
 {
        IMPEG2D_ERROR_CODES_T e_error = IMPEG2D_FRM_HDR_DECODE_ERR;
 return e_error;
 }
 if ((u2_width != ps_dec->u2_horizontal_size)
 || (u2_height != ps_dec->u2_vertical_size))
 {
 if (0 == ps_dec->u2_header_done)
 {
             ps_dec->u2_horizontal_size = u2_width;
             ps_dec->u2_vertical_size = u2_height;
            if (0 == ps_dec->u4_frm_buf_stride)
            {
                ps_dec->u4_frm_buf_stride  = (UWORD32) (u2_width);
            }
         }
         else
         {
 if (0 == ps_dec->i4_pic_count)
 {
 return (IMPEG2D_ERROR_CODES_T) IMPEG2D_FRM_HDR_DECODE_ERR;
 }
 else if((u2_width > ps_dec->u2_create_max_width)
 || (u2_height > ps_dec->u2_create_max_height))
 {
                IMPEG2D_ERROR_CODES_T e_error = IMPEG2D_UNSUPPORTED_DIMENSIONS;
                ps_dec->u2_reinit_max_height   = u2_height;
                ps_dec->u2_reinit_max_width    = u2_width;
                 return e_error;
             }
             else
             {
 return (IMPEG2D_ERROR_CODES_T)IVD_RES_CHANGED;
 }
 }
 }
 if((ps_dec->u2_horizontal_size > ps_dec->u2_create_max_width)
 || (ps_dec->u2_vertical_size > ps_dec->u2_create_max_height))
 {
        IMPEG2D_ERROR_CODES_T e_error = IMPEG2D_UNSUPPORTED_DIMENSIONS;
        ps_dec->u2_reinit_max_height   = ps_dec->u2_vertical_size;
        ps_dec->u2_reinit_max_width    = ps_dec->u2_horizontal_size;
         return e_error;
     }
    ps_dec->u2_aspect_ratio_info = impeg2d_bit_stream_get(ps_stream,4);
    ps_dec->u2_frame_rate_code = impeg2d_bit_stream_get(ps_stream,4);
 if (ps_dec->u2_frame_rate_code > MPEG2_MAX_FRAME_RATE_CODE)
 {
 return IMPEG2D_FRM_HDR_DECODE_ERR;
 }
    impeg2d_bit_stream_flush(ps_stream,18);
    GET_MARKER_BIT(ps_dec,ps_stream);
    impeg2d_bit_stream_flush(ps_stream,11);
 if(impeg2d_bit_stream_get_bit(ps_stream) == 1)
 {
        UWORD16 i;
 for(i = 0; i < NUM_PELS_IN_BLOCK; i++)
 {
            ps_dec->au1_intra_quant_matrix[gau1_impeg2_inv_scan_zig_zag[i]] = (UWORD8)impeg2d_bit_stream_get(ps_stream,8);
 }
 }
 else
 {
        memcpy(ps_dec->au1_intra_quant_matrix,gau1_impeg2_intra_quant_matrix_default,
                NUM_PELS_IN_BLOCK);
 }
 if(impeg2d_bit_stream_get_bit(ps_stream) == 1)
 {
        UWORD16 i;
 for(i = 0; i < NUM_PELS_IN_BLOCK; i++)
 {
            ps_dec->au1_inter_quant_matrix[gau1_impeg2_inv_scan_zig_zag[i]] = (UWORD8)impeg2d_bit_stream_get(ps_stream,8);
 }
 }
 else
 {
        memcpy(ps_dec->au1_inter_quant_matrix,gau1_impeg2_inter_quant_matrix_default,
            NUM_PELS_IN_BLOCK);
 }
    impeg2d_next_start_code(ps_dec);
 return (IMPEG2D_ERROR_CODES_T)IVD_ERROR_NONE;
}

iakerb_parse_token(iakerb_ctx_id_t ctx,
                   int initialContextToken,
                   const gss_buffer_t token,
                   krb5_data *realm,
                   krb5_data **cookie,
                   krb5_data *request)
{
    krb5_error_code code;
    krb5_iakerb_header *iah = NULL;
    unsigned int bodysize, lenlen;
    int length;
    unsigned char *ptr;
    int flags = 0;
    krb5_data data;
    if (token == GSS_C_NO_BUFFER || token->length == 0) {
        code = KRB5_BAD_MSIZE;
        goto cleanup;
    }
    if (initialContextToken)
        flags |= G_VFY_TOKEN_HDR_WRAPPER_REQUIRED;
    ptr = token->value;
    code = g_verify_token_header(gss_mech_iakerb,
                                 &bodysize, &ptr,
                                 IAKERB_TOK_PROXY,
                                 token->length, flags);
    if (code != 0)
        goto cleanup;
    data.data = (char *)ptr;
    if (bodysize-- == 0 || *ptr++ != 0x30 /* SEQUENCE */) {
        code = ASN1_BAD_ID;
        goto cleanup;
    }
    length = gssint_get_der_length(&ptr, bodysize, &lenlen);
    if (length < 0 || bodysize - lenlen < (unsigned int)length) {
        code = KRB5_BAD_MSIZE;
        goto cleanup;
    }
    data.length = 1 /* SEQUENCE */ + lenlen + length;
    ptr += length;
    bodysize -= (lenlen + length);
    code = decode_krb5_iakerb_header(&data, &iah);
    if (code != 0)
        goto cleanup;
    if (realm != NULL) {
        iah->target_realm.data = NULL;
    }
    if (cookie != NULL) {
        iah->cookie = NULL;
    }
    request->data = (char *)ptr;
    request->length = bodysize;
    assert(request->data + request->length ==
           (char *)token->value + token->length);
cleanup:
    krb5_free_iakerb_header(ctx->k5c, iah);
    return code;
}

static unsigned long copy_semid_to_user(void __user *buf, struct semid64_ds *in, int version)
{
	switch(version) {
	case IPC_64:
		return copy_to_user(buf, in, sizeof(*in));
	case IPC_OLD:
	    {
		struct semid_ds out;
		memset(&out, 0, sizeof(out));
		ipc64_perm_to_ipc_perm(&in->sem_perm, &out.sem_perm);
		out.sem_otime	= in->sem_otime;
		out.sem_ctime	= in->sem_ctime;
		out.sem_nsems	= in->sem_nsems;
		return copy_to_user(buf, &out, sizeof(out));
	    }
	default:
		return -EINVAL;
	}
}

