static void vmx_hwapic_irr_update(struct kvm_vcpu *vcpu, int max_irr)
{
	if (max_irr == -1)
		return;
	if (is_guest_mode(vcpu) && nested_exit_on_intr(vcpu))
		return;
	if (!is_guest_mode(vcpu)) {
		vmx_set_rvi(max_irr);
