   EXPECT_EQ(LifecycleUnitState::ACTIVE,
             background_lifecycle_unit->GetState());
   EXPECT_TRUE(tab_strip_model_->GetWebContentsAt(0)
                  ->GetController()
                  .GetPendingEntry());
}

