static int nl80211_tx_mgmt_cancel_wait(struct sk_buff *skb, struct genl_info *info)
{
	struct cfg80211_registered_device *rdev = info->user_ptr[0];
	struct net_device *dev = info->user_ptr[1];
	u64 cookie;
	if (!info->attrs[NL80211_ATTR_COOKIE])
		return -EINVAL;
	if (!rdev->ops->mgmt_tx_cancel_wait)
		return -EOPNOTSUPP;
	if (dev->ieee80211_ptr->iftype != NL80211_IFTYPE_STATION &&
	    dev->ieee80211_ptr->iftype != NL80211_IFTYPE_ADHOC &&
	    dev->ieee80211_ptr->iftype != NL80211_IFTYPE_P2P_CLIENT &&
	    dev->ieee80211_ptr->iftype != NL80211_IFTYPE_AP &&
	    dev->ieee80211_ptr->iftype != NL80211_IFTYPE_AP_VLAN &&
	    dev->ieee80211_ptr->iftype != NL80211_IFTYPE_P2P_GO)
		return -EOPNOTSUPP;
	cookie = nla_get_u64(info->attrs[NL80211_ATTR_COOKIE]);
	return rdev->ops->mgmt_tx_cancel_wait(&rdev->wiphy, dev, cookie);
}

int main(int argc, char **argv) {
  FILE *infile = NULL;
 VpxVideoWriter *writer = NULL;
  vpx_codec_ctx_t codec;
  vpx_codec_enc_cfg_t cfg;
  vpx_image_t raw;
  vpx_codec_err_t res;
 vpx_fixed_buf_t stats = {0};
 VpxVideoInfo info = {0};
  const VpxInterface *encoder = NULL;
 int pass;
  const int fps = 30;        // TODO(dkovalev) add command line argument
  const int bitrate = 200;   // kbit/s TODO(dkovalev) add command line argument
  const char *const codec_arg = argv[1];
const char *const width_arg = argv[2];
const char *const height_arg = argv[3];
const char *const infile_arg = argv[4];
const char *const outfile_arg = argv[5];
 exec_name = argv[0];
if (argc != 6)
   die("Invalid number of arguments.");
 encoder = get_vpx_encoder_by_name(codec_arg);
  if (!encoder)
    die("Unsupported codec.");
 info.codec_fourcc = encoder->fourcc;
 info.time_base.numerator = 1;
 info.time_base.denominator = fps;
 info.frame_width = strtol(width_arg, NULL, 0);
 info.frame_height = strtol(height_arg, NULL, 0);
 if (info.frame_width <= 0 ||
     info.frame_height <= 0 ||
     (info.frame_width % 2) != 0 ||
     (info.frame_height % 2) != 0) {
   die("Invalid frame size: %dx%d", info.frame_width, info.frame_height);
 }
 if (!vpx_img_alloc(&raw, VPX_IMG_FMT_I420, info.frame_width,
                                            info.frame_height, 1)) {
   die("Failed to allocate image", info.frame_width, info.frame_height);
 }
 writer = vpx_video_writer_open(outfile_arg, kContainerIVF, &info);
 if (!writer)
   die("Failed to open %s for writing", outfile_arg);
 printf("Using %s\n", vpx_codec_iface_name(encoder->interface()));
 res = vpx_codec_enc_config_default(encoder->interface(), &cfg, 0);
  if (res)
    die_codec(&codec, "Failed to get default codec config.");
 cfg.g_w = info.frame_width;
 cfg.g_h = info.frame_height;
 cfg.g_timebase.num = info.time_base.numerator;
 cfg.g_timebase.den = info.time_base.denominator;
  cfg.rc_target_bitrate = bitrate;
 for (pass = 0; pass < 2; ++pass) {
   int frame_count = 0;
   if (pass == 0) {
     cfg.g_pass = VPX_RC_FIRST_PASS;
   } else {
     cfg.g_pass = VPX_RC_LAST_PASS;
     cfg.rc_twopass_stats_in = stats;
   }
   if (!(infile = fopen(infile_arg, "rb")))
     die("Failed to open %s for reading", infile_arg);
   if (vpx_codec_enc_init(&codec, encoder->interface(), &cfg, 0))
     die_codec(&codec, "Failed to initialize encoder");
   while (vpx_img_read(&raw, infile)) {
     ++frame_count;
     if (pass == 0) {
       get_frame_stats(&codec, &raw, frame_count, 1, 0, VPX_DL_BEST_QUALITY,
                       &stats);
     } else {
       encode_frame(&codec, &raw, frame_count, 1, 0, VPX_DL_BEST_QUALITY,
                    writer);
     }
   }
   if (pass == 0) {
     get_frame_stats(&codec, NULL, frame_count, 1, 0, VPX_DL_BEST_QUALITY,
                     &stats);
   } else {
     printf("\n");
   }
   fclose(infile);
   printf("Pass %d complete. Processed %d frames.\n", pass + 1, frame_count);
   if (vpx_codec_destroy(&codec))
     die_codec(&codec, "Failed to destroy codec.");
 }
 vpx_img_free(&raw);
  free(stats.buf);
 vpx_video_writer_close(writer);
  return EXIT_SUCCESS;
}

static int idle_balance(struct rq *this_rq, struct rq_flags *rf)
{
	unsigned long next_balance = jiffies + HZ;
	int this_cpu = this_rq->cpu;
	struct sched_domain *sd;
	int pulled_task = 0;
	u64 curr_cost = 0;
	this_rq->idle_stamp = rq_clock(this_rq);
	if (!cpu_active(this_cpu))
		return 0;
	rq_unpin_lock(this_rq, rf);
	if (this_rq->avg_idle < sysctl_sched_migration_cost ||
	    !READ_ONCE(this_rq->rd->overload)) {
		rcu_read_lock();
		sd = rcu_dereference_check_sched_domain(this_rq->sd);
		if (sd)
			update_next_balance(sd, &next_balance);
		rcu_read_unlock();
		nohz_newidle_balance(this_rq);
		goto out;
	}
	raw_spin_unlock(&this_rq->lock);
	update_blocked_averages(this_cpu);
	rcu_read_lock();
	for_each_domain(this_cpu, sd) {
		int continue_balancing = 1;
		u64 t0, domain_cost;
		if (!(sd->flags & SD_LOAD_BALANCE))
			continue;
		if (this_rq->avg_idle < curr_cost + sd->max_newidle_lb_cost) {
			update_next_balance(sd, &next_balance);
			break;
		}
		if (sd->flags & SD_BALANCE_NEWIDLE) {
			t0 = sched_clock_cpu(this_cpu);
			pulled_task = load_balance(this_cpu, this_rq,
						   sd, CPU_NEWLY_IDLE,
						   &continue_balancing);
			domain_cost = sched_clock_cpu(this_cpu) - t0;
			if (domain_cost > sd->max_newidle_lb_cost)
				sd->max_newidle_lb_cost = domain_cost;
			curr_cost += domain_cost;
		}
		update_next_balance(sd, &next_balance);
		if (pulled_task || this_rq->nr_running > 0)
			break;
	}
	rcu_read_unlock();
	raw_spin_lock(&this_rq->lock);
	if (curr_cost > this_rq->max_idle_balance_cost)
		this_rq->max_idle_balance_cost = curr_cost;
out:
	if (this_rq->cfs.h_nr_running && !pulled_task)
		pulled_task = 1;
	if (time_after(this_rq->next_balance, next_balance))
		this_rq->next_balance = next_balance;
	if (this_rq->nr_running != this_rq->cfs.h_nr_running)
		pulled_task = -1;
	if (pulled_task)
		this_rq->idle_stamp = 0;
	rq_repin_lock(this_rq, rf);
	return pulled_task;
}

static struct snd_timer *snd_timer_find(struct snd_timer_id *tid)
{
	struct snd_timer *timer = NULL;
	list_for_each_entry(timer, &snd_timer_list, device_list) {
		if (timer->tmr_class != tid->dev_class)
			continue;
		if ((timer->tmr_class == SNDRV_TIMER_CLASS_CARD ||
		     timer->tmr_class == SNDRV_TIMER_CLASS_PCM) &&
		    (timer->card == NULL ||
		     timer->card->number != tid->card))
			continue;
		if (timer->tmr_device != tid->device)
			continue;
		if (timer->tmr_subdevice != tid->subdevice)
			continue;
		return timer;
	}
	return NULL;
}

R_API RList *r_bin_file_get_strings(RBinFile *a, int min, int dump) {
	RListIter *iter;
	RBinSection *section;
	RBinObject *o = a? a->o: NULL;
	RList *ret;
	if (dump) {
		ret = NULL;
	} else {
		ret = r_list_newf (r_bin_string_free);
		if (!ret) {
			return NULL;
		}
	}
	if (o && o->sections && !r_list_empty (o->sections) && !a->rawstr) {
		r_list_foreach (o->sections, iter, section) {
			if (is_data_section (a, section)) {
				r_bin_file_get_strings_range (a, ret, min, section->paddr,
						section->paddr + section->size);
			}
		}
		r_list_foreach (o->sections, iter, section) {
			RBinString *s;
			RListIter *iter2;
			const int bits = (a->o && a->o->info) ? a->o->info->bits : 32;
			const int cfstr_size = (bits == 64) ? 32 : 16;
			const int cfstr_offs = (bits == 64) ? 16 :  8;
			if (strstr (section->name, "__cfstring")) {
				int i;
				ut8 *p;
				for (i = 0; i < section->size; i += cfstr_size) {
					ut8 buf[32];
					if (!r_buf_read_at (
						    a->buf, section->paddr + i + cfstr_offs,
						    buf, sizeof (buf))) {
						break;
					}
					p = buf;
					ut64 cfstr_vaddr = section->vaddr + i;
					ut64 cstr_vaddr = (bits == 64)
								   ? r_read_le64 (p)
								   : r_read_le32 (p);
					r_list_foreach (ret, iter2, s) {
						if (s->vaddr == cstr_vaddr) {
							RBinString *bs = R_NEW0 (RBinString);
							if (bs) {
								bs->type = s->type;
								bs->length = s->length;
								bs->size = s->size;
								bs->ordinal = s->ordinal;
								bs->paddr = bs->vaddr = cfstr_vaddr;
								bs->string = r_str_newf ("cstr.%s", s->string);
								r_list_append (ret, bs);
							}
							break;
						}
					}
				}
			}
		}
	} else {
		if (a) {
			r_bin_file_get_strings_range (a, ret, min, 0, a->size);
		}
	}
	return ret;
}

