void GDataCacheMetadataMap::ScanCacheDirectory(
    const std::vector<FilePath>& cache_paths,
    GDataCache::CacheSubDirectoryType sub_dir_type,
   CacheMap* cache_map,
   ResourceIdToFilePathMap* processed_file_map) {
 DCHECK(cache_map);
 DCHECK(processed_file_map);
  file_util::FileEnumerator enumerator(
      cache_paths[sub_dir_type],
      false,  // not recursive
     static_cast<file_util::FileEnumerator::FileType>(
         file_util::FileEnumerator::FILES |
         file_util::FileEnumerator::SHOW_SYM_LINKS),
     util::kWildCard);
 for (FilePath current = enumerator.Next(); !current.empty();
      current = enumerator.Next()) {
   std::string resource_id;
   std::string md5;
   std::string extra_extension;
   util::ParseCacheFilePath(current, &resource_id, &md5, &extra_extension);
   int cache_state = GDataCache::CACHE_STATE_NONE;
    if (sub_dir_type == GDataCache::CACHE_TYPE_PINNED) {
     std::string reason;
     if (!IsValidSymbolicLink(current, sub_dir_type, cache_paths, &reason)) {
       LOG(WARNING) << "Removing an invalid symlink: " << current.value()
                    << ": " << reason;
       util::DeleteSymlink(current);
       continue;
     }
      CacheMap::iterator iter = cache_map->find(resource_id);
      if (iter != cache_map->end()) {  // Entry exists, update pinned state.
        iter->second.cache_state =
            GDataCache::SetCachePinned(iter->second.cache_state);
       processed_file_map->insert(std::make_pair(resource_id, current));
        continue;
      }
      cache_state = GDataCache::SetCachePinned(cache_state);
    } else if (sub_dir_type == GDataCache::CACHE_TYPE_OUTGOING) {
     std::string reason;
     if (!IsValidSymbolicLink(current, sub_dir_type, cache_paths, &reason)) {
       LOG(WARNING) << "Removing an invalid symlink: " << current.value()
                    << ": " << reason;
       util::DeleteSymlink(current);
       continue;
     }
      CacheMap::iterator iter = cache_map->find(resource_id);
     if (iter == cache_map->end() || !iter->second.IsDirty()) {
       LOG(WARNING) << "Removing an symlink to a non-dirty file: "
                    << current.value();
       util::DeleteSymlink(current);
       continue;
     }
     processed_file_map->insert(std::make_pair(resource_id, current));
     continue;
   } else if (sub_dir_type == GDataCache::CACHE_TYPE_PERSISTENT ||
              sub_dir_type == GDataCache::CACHE_TYPE_TMP) {
     FilePath unused;
     if (file_util::ReadSymbolicLink(current, &unused)) {
       LOG(WARNING) << "Removing a symlink in persistent/tmp directory"
                    << current.value();
       util::DeleteSymlink(current);
       continue;
     }
     if (extra_extension == util::kMountedArchiveFileExtension) {
       DCHECK(sub_dir_type == GDataCache::CACHE_TYPE_PERSISTENT);
       file_util::Delete(current, false);
      } else {
       cache_state = GDataCache::SetCachePresent(cache_state);
       if (md5 == util::kLocallyModifiedFileExtension) {
         if (sub_dir_type == GDataCache::CACHE_TYPE_PERSISTENT) {
           cache_state |= GDataCache::SetCacheDirty(cache_state);
         } else {
           LOG(WARNING) << "Removing a dirty file in tmp directory: "
                        << current.value();
           file_util::Delete(current, false);
           continue;
         }
       }
      }
    } else {
     NOTREACHED() << "Unexpected sub directory type: " << sub_dir_type;
    }
    cache_map->insert(std::make_pair(
        resource_id, GDataCache::CacheEntry(md5, sub_dir_type, cache_state)));
   processed_file_map->insert(std::make_pair(resource_id, current));
  }
}

Line_Up( RAS_ARGS Long  x1,
                  Long  y1,
                  Long  x2,
                  Long  y2,
                  Long  miny,
                  Long  maxy )
{
  Long   Dx, Dy;
  Int    e1, e2, f1, f2, size;     /* XXX: is `Short' sufficient? */
  Long   Ix, Rx, Ax;
  PLong  top;
  Dx = x2 - x1;
  Dy = y2 - y1;
  if ( Dy <= 0 || y2 < miny || y1 > maxy )
    return SUCCESS;
  if ( y1 < miny )
  {
    x1 += SMulDiv( Dx, miny - y1, Dy );
    e1  = (Int)TRUNC( miny );
    f1  = 0;
  }
  else
  {
    e1 = (Int)TRUNC( y1 );
    f1 = (Int)FRAC( y1 );
  }
  if ( y2 > maxy )
  {
    e2  = (Int)TRUNC( maxy );
    f2  = 0;
  }
  else
  {
    e2 = (Int)TRUNC( y2 );
    f2 = (Int)FRAC( y2 );
  }
  if ( f1 > 0 )
  {
    if ( e1 == e2 )
      return SUCCESS;
    else
    {
      x1 += SMulDiv( Dx, ras.precision - f1, Dy );
      e1 += 1;
    }
  }
  else
    if ( ras.joint )
    {
      ras.top--;
      ras.joint = FALSE;
    }
  ras.joint = (char)( f2 == 0 );
  if ( ras.fresh )
  {
    ras.cProfile->start = e1;
    ras.fresh           = FALSE;
  }
  size = e2 - e1 + 1;
  if ( ras.top + size >= ras.maxBuff )
  {
    ras.error = FT_THROW( Overflow );
    return FAILURE;
  }
  if ( Dx > 0 )
  {
    Ix = SMulDiv_No_Round( ras.precision, Dx, Dy );
    Rx = ( ras.precision * Dx ) % Dy;
    Dx = 1;
  }
  else
  {
    Ix = -SMulDiv_No_Round( ras.precision, -Dx, Dy );
    Rx = ( ras.precision * -Dx ) % Dy;
    Dx = -1;
  }
  Ax  = -Dy;
  top = ras.top;
  while ( size > 0 )
  {
    x1 += Ix;
    Ax += Rx;
    if ( Ax >= 0 )
    {
      Ax -= Dy;
      x1 += Dx;
    }
    size--;
  }
  ras.top = top;
  return SUCCESS;
}

long long Cluster::GetLastTime() const
{
    const BlockEntry* pEntry;
    const long status = GetLast(pEntry);
    if (status < 0)  //error
        return status;
    if (pEntry == NULL)  //empty cluster
        return GetTime();
    const Block* const pBlock = pEntry->GetBlock();
    assert(pBlock);
    return pBlock->GetTime(this);
}

size_t NormalPage::objectPayloadSizeForTesting() {
  size_t objectPayloadSize = 0;
  Address headerAddress = payload();
  markAsSwept();
  ASSERT(headerAddress != payloadEnd());
  do {
     HeapObjectHeader* header =
         reinterpret_cast<HeapObjectHeader*>(headerAddress);
     if (!header->isFree()) {
      ASSERT(header->checkHeader());
       objectPayloadSize += header->payloadSize();
     }
     ASSERT(header->size() < blinkPagePayloadSize());
    headerAddress += header->size();
    ASSERT(headerAddress <= payloadEnd());
  } while (headerAddress < payloadEnd());
  return objectPayloadSize;
}

lldp_private_8023_print(netdissect_options *ndo,
                        const u_char *tptr, u_int tlv_len)
{
    int subtype, hexdump = FALSE;
    if (tlv_len < 4) {
        return hexdump;
    }
    subtype = *(tptr+3);
    ND_PRINT((ndo, "\n\t  %s Subtype (%u)",
           tok2str(lldp_8023_subtype_values, "unknown", subtype),
           subtype));
    switch (subtype) {
    case LLDP_PRIVATE_8023_SUBTYPE_MACPHY:
        if (tlv_len < 9) {
            return hexdump;
        }
        ND_PRINT((ndo, "\n\t    autonegotiation [%s] (0x%02x)",
               bittok2str(lldp_8023_autonegotiation_values, "none", *(tptr+4)),
        ND_PRINT((ndo, "\n\t    PMD autoneg capability [%s] (0x%04x)",
               bittok2str(lldp_pmd_capability_values,"unknown", EXTRACT_16BITS(tptr+5)),
               EXTRACT_16BITS(tptr + 5)));
        ND_PRINT((ndo, "\n\t    MAU type %s (0x%04x)",
               tok2str(lldp_mau_types_values, "unknown", EXTRACT_16BITS(tptr+7)),
               EXTRACT_16BITS(tptr + 7)));
        break;
    case LLDP_PRIVATE_8023_SUBTYPE_MDIPOWER:
        if (tlv_len < 7) {
            return hexdump;
        }
        ND_PRINT((ndo, "\n\t    MDI power support [%s], power pair %s, power class %s",
               bittok2str(lldp_mdi_values, "none", *(tptr+4)),
               tok2str(lldp_mdi_power_pairs_values, "unknown", *(tptr+5)),
               tok2str(lldp_mdi_power_class_values, "unknown", *(tptr + 6))));
        break;
    case LLDP_PRIVATE_8023_SUBTYPE_LINKAGGR:
        if (tlv_len < 9) {
            return hexdump;
        }
        ND_PRINT((ndo, "\n\t    aggregation status [%s], aggregation port ID %u",
               bittok2str(lldp_aggregation_values, "none", *(tptr+4)),
               EXTRACT_32BITS(tptr + 5)));
         break;
     case LLDP_PRIVATE_8023_SUBTYPE_MTU:
         ND_PRINT((ndo, "\n\t    MTU size %u", EXTRACT_16BITS(tptr + 4)));
         break;
    default:
        hexdump = TRUE;
        break;
    }
    return hexdump;
}

