int dns_hostname_validation(const char *string, char **err)
{
	const char *c, *d;
	int i;
	if (strlen(string) > DNS_MAX_NAME_SIZE) {
		if (err)
		return 0;
	}
	c = string;
	while (*c) {
		d = c;
		i = 0;
		while (*d != '.' && *d && i <= DNS_MAX_LABEL_SIZE) {
			i++;
			if (!((*d == '-') || (*d == '_') ||
			      ((*d >= 'a') && (*d <= 'z')) ||
			      ((*d >= 'A') && (*d <= 'Z')) ||
			      ((*d >= '0') && (*d <= '9')))) {
				if (err)
				return 0;
			}
			d++;
		}
		if ((i >= DNS_MAX_LABEL_SIZE) && (d[i] != '.')) {
			if (err)
			return 0;
		}
		if (*d == '\0')
			goto out;
		c = ++d;
	}
 out:
	return 1;
}

long join_session_keyring(const char *name)
{
	const struct cred *old;
	struct cred *new;
	struct key *keyring;
	long ret, serial;
	new = prepare_creds();
	if (!new)
		return -ENOMEM;
	old = current_cred();
	if (!name) {
		ret = install_session_keyring_to_cred(new, NULL);
		if (ret < 0)
			goto error;
		serial = new->session_keyring->serial;
		ret = commit_creds(new);
		if (ret == 0)
			ret = serial;
		goto okay;
	}
	mutex_lock(&key_session_mutex);
	keyring = find_keyring_by_name(name, false);
	if (PTR_ERR(keyring) == -ENOKEY) {
		keyring = keyring_alloc(
			name, old->uid, old->gid, old,
			KEY_POS_ALL | KEY_USR_VIEW | KEY_USR_READ | KEY_USR_LINK,
			KEY_ALLOC_IN_QUOTA, NULL);
		if (IS_ERR(keyring)) {
			ret = PTR_ERR(keyring);
			goto error2;
		}
	} else if (IS_ERR(keyring)) {
		ret = PTR_ERR(keyring);
		goto error2;
	} else if (keyring == new->session_keyring) {
		ret = 0;
		goto error2;
	}
	ret = install_session_keyring_to_cred(new, keyring);
	if (ret < 0)
		goto error2;
	commit_creds(new);
	mutex_unlock(&key_session_mutex);
	ret = keyring->serial;
	key_put(keyring);
okay:
	return ret;
error2:
	mutex_unlock(&key_session_mutex);
error:
	abort_creds(new);
	return ret;
}

iasecc_pin_cmd(struct sc_card *card, struct sc_pin_cmd_data *data, int *tries_left)
{
	struct sc_context *ctx = card->ctx;
	int rv;
	LOG_FUNC_CALLED(ctx);
	sc_log(ctx, "iasecc_pin_cmd() cmd 0x%X, PIN type 0x%X, PIN reference %i, PIN-1 %p:%i, PIN-2 %p:%i",
			data->cmd, data->pin_type, data->pin_reference,
			data->pin1.data, data->pin1.len, data->pin2.data, data->pin2.len);
	switch (data->cmd)   {
	case SC_PIN_CMD_VERIFY:
		rv = iasecc_pin_verify(card, data->pin_type, data->pin_reference, data->pin1.data, data->pin1.len, tries_left);
		break;
	case SC_PIN_CMD_CHANGE:
		if (data->pin_type == SC_AC_AUT)
			rv = iasecc_keyset_change(card, data, tries_left);
		else
			rv = iasecc_pin_change(card, data, tries_left);
		break;
	case SC_PIN_CMD_UNBLOCK:
		rv = iasecc_pin_reset(card, data, tries_left);
		break;
	case SC_PIN_CMD_GET_INFO:
		rv = iasecc_pin_get_policy(card, data);
		break;
	default:
		sc_log(ctx, "Other pin commands not supported yet: 0x%X", data->cmd);
		rv = SC_ERROR_NOT_SUPPORTED;
	}
	LOG_FUNC_RETURN(ctx, rv);
}

int crypto_unregister_instance(struct crypto_alg *alg)
{
	int err;
	struct crypto_instance *inst = (void *)alg;
	struct crypto_template *tmpl = inst->tmpl;
	LIST_HEAD(users);
	if (!(alg->cra_flags & CRYPTO_ALG_INSTANCE))
		return -EINVAL;
	BUG_ON(atomic_read(&alg->cra_refcnt) != 1);
	down_write(&crypto_alg_sem);
	hlist_del_init(&inst->list);
	err = crypto_remove_alg(alg, &users);
	up_write(&crypto_alg_sem);
	if (err)
		return err;
	tmpl->free(inst);
	crypto_remove_final(&users);
	return 0;
}

