    die("Invalid frame size: %dx%d", info.frame_width, info.frame_height);
 }
 if (!vpx_img_alloc(&raw, VPX_IMG_FMT_I420, info.frame_width,
                                             info.frame_height, 1)) {
     die("Failed to allocate image.");
   }
  printf("Using %s\n", vpx_codec_iface_name(encoder->interface()));
  res = vpx_codec_enc_config_default(encoder->interface(), &cfg, 0);
   if (res)
     die_codec(&codec, "Failed to get default codec config.");
  cfg.g_w = info.frame_width;
  cfg.g_h = info.frame_height;
  cfg.g_timebase.num = info.time_base.numerator;
  cfg.g_timebase.den = info.time_base.denominator;
  cfg.rc_target_bitrate = bitrate;
  writer = vpx_video_writer_open(argv[4], kContainerIVF, &info);
 if (!writer)
    die("Failed to open %s for writing.", argv[4]);
   if (!(infile = fopen(argv[3], "rb")))
     die("Failed to open %s for reading.", argv[3]);
  if (vpx_codec_enc_init(&codec, encoder->interface(), &cfg, 0))
     die_codec(&codec, "Failed to initialize encoder");
   while (vpx_img_read(&raw, infile)) {
     if (frame_count + 1 == update_frame_num) {
       vpx_ref_frame_t ref;
      ref.frame_type = VP8_LAST_FRAME;
      ref.img = raw;
 if (vpx_codec_control(&codec, VP8_SET_REFERENCE, &ref))
        die_codec(&codec, "Failed to set reference frame");
 }
     encode_frame(&codec, &raw, frame_count++, writer);
   }
  encode_frame(&codec, NULL, -1, writer);
   printf("\n");
   fclose(infile);
  printf("Processed %d frames.\n", frame_count);
  vpx_img_free(&raw);
 if (vpx_codec_destroy(&codec))
    die_codec(&codec, "Failed to destroy codec.");
  vpx_video_writer_close(writer);
 return EXIT_SUCCESS;
}

static uint32_t yuv_to_rgba(uint32_t ycbcr)
{
    uint8_t r, g, b;
    int y, cb, cr;
    y  = (ycbcr >> 16) & 0xFF;
    cr = (ycbcr >> 8)  & 0xFF;
    cb =  ycbcr        & 0xFF;
    b = av_clip_uint8((1164 * (y - 16)                     + 2018 * (cb - 128)) / 1000);
    g = av_clip_uint8((1164 * (y - 16) -  813 * (cr - 128) -  391 * (cb - 128)) / 1000);
    r = av_clip_uint8((1164 * (y - 16) + 1596 * (cr - 128)                    ) / 1000);
    return (r << 16) | (g << 8) | b;
}

static ssize_t cqspi_read(struct spi_nor *nor, loff_t from,
			  size_t len, u_char *buf)
{
	int ret;
	ret = cqspi_set_protocol(nor, 1);
	if (ret)
		return ret;
	ret = cqspi_indirect_read_setup(nor, from);
	if (ret)
		return ret;
	ret = cqspi_indirect_read_execute(nor, buf, len);
	if (ret)
		return ret;
	return (ret < 0) ? ret : len;
}

