static UINT32 nsc_rle_encode(BYTE* in, BYTE* out, UINT32 originalSize)
 {
 	UINT32 left;
 	UINT32 runlength = 1;
	UINT32 planeSize = 0;
	left = originalSize;
	while (left > 4 && planeSize < originalSize - 4)
	{
		if (left > 5 && *in == *(in + 1))
		{
			runlength++;
		}
		else if (runlength == 1)
		{
			planeSize++;
		}
		else if (runlength < 256)
		{
			runlength = 1;
			planeSize += 3;
		}
		else
		{
			runlength = 1;
			planeSize += 7;
		}
		in++;
		left--;
	}
	if (planeSize < originalSize - 4)
		CopyMemory(out, in, 4);
	planeSize += 4;
	return planeSize;
}

