static int digest_encode(const char *src, int len, char *dst)
{
	int i = 0, bits = 0, ac = 0;
	char *cp = dst;
	while (i < len) {
		ac += (((unsigned char) src[i]) << bits);
		bits += 8;
		do {
			ac >>= 6;
			bits -= 6;
		} while (bits >= 6);
		i++;
	}
	if (bits)
	return cp - dst;
}

