int dtls1_get_record(SSL *s)
	{
	int ssl_major,ssl_minor;
	int i,n;
	SSL3_RECORD *rr;
	unsigned char *p = NULL;
	unsigned short version;
	DTLS1_BITMAP *bitmap;
	unsigned int is_next_epoch;
	rr= &(s->s3->rrec);
	dtls1_process_buffered_records(s);
	if (dtls1_get_processed_record(s))
		return 1;
again:
	if (	(s->rstate != SSL_ST_READ_BODY) ||
		(s->packet_length < DTLS1_RT_HEADER_LENGTH)) 
		{
		n=ssl3_read_n(s, DTLS1_RT_HEADER_LENGTH, s->s3->rbuf.len, 0);
		if (n <= 0) return(n); /* error or non-blocking */
		if (s->packet_length != DTLS1_RT_HEADER_LENGTH)
			{
			s->packet_length = 0;
			goto again;
			}
		s->rstate=SSL_ST_READ_BODY;
		p=s->packet;
		if (s->msg_callback)
			s->msg_callback(0, 0, SSL3_RT_HEADER, p, DTLS1_RT_HEADER_LENGTH, s, s->msg_callback_arg);
		rr->type= *(p++);
		ssl_major= *(p++);
		ssl_minor= *(p++);
		version=(ssl_major<<8)|ssl_minor;
		n2s(p,rr->epoch);
		memcpy(&(s->s3->read_sequence[2]), p, 6);
		p+=6;
		n2s(p,rr->length);
		if (!s->first_packet)
			{
			if (version != s->version)
				{
				rr->length = 0;
				s->packet_length = 0;
				goto again;
				}
			}
		if ((version & 0xff00) != (s->version & 0xff00))
			{
			rr->length = 0;
			s->packet_length = 0;
			goto again;
			}
		if (rr->length > SSL3_RT_MAX_ENCRYPTED_LENGTH)
			{
			rr->length = 0;
			s->packet_length = 0;
			goto again;
			}
		}
	if (rr->length > s->packet_length-DTLS1_RT_HEADER_LENGTH)
		{
		i=rr->length;
		n=ssl3_read_n(s,i,i,1);
		if ( n != i)
			{
			rr->length = 0;
			s->packet_length = 0;
			goto again;
			}
		}
	s->rstate=SSL_ST_READ_HEADER; /* set state for later operations */
	bitmap = dtls1_get_bitmap(s, rr, &is_next_epoch);
	if ( bitmap == NULL)
		{
		rr->length = 0;
		s->packet_length = 0;  /* dump this record */
		goto again;   /* get another record */
		}
#ifndef OPENSSL_NO_SCTP
	if (!BIO_dgram_is_sctp(SSL_get_rbio(s)))
  		{
#endif
 		if (!(s->d1->listen && rr->type == SSL3_RT_HANDSHAKE &&
 		    !dtls1_record_replay_check(s, bitmap))
 			{
 			rr->length = 0;
			s->packet_length=0; /* dump this record */
			goto again;     /* get another record */
			}
#ifndef OPENSSL_NO_SCTP
  		}
#endif
	if (rr->length == 0) goto again;
	if (is_next_epoch)
		{
		if ((SSL_in_init(s) || s->in_handshake) && !s->d1->listen)
			{
			dtls1_buffer_record(s, &(s->d1->unprocessed_rcds), rr->seq_num);
			}
		rr->length = 0;
		s->packet_length = 0;
		goto again;
		}
	if (!dtls1_process_record(s))
		{
		rr->length = 0;
		s->packet_length = 0;  /* dump this record */
		goto again;   /* get another record */
		}
	return(1);
	}

ext4_get_acl(struct inode *inode, int type)
{
	int name_index;
	char *value = NULL;
	struct posix_acl *acl;
	int retval;
	switch (type) {
	case ACL_TYPE_ACCESS:
		name_index = EXT4_XATTR_INDEX_POSIX_ACL_ACCESS;
		break;
	case ACL_TYPE_DEFAULT:
		name_index = EXT4_XATTR_INDEX_POSIX_ACL_DEFAULT;
		break;
	default:
		BUG();
	}
	retval = ext4_xattr_get(inode, name_index, "", NULL, 0);
	if (retval > 0) {
		value = kmalloc(retval, GFP_NOFS);
		if (!value)
			return ERR_PTR(-ENOMEM);
		retval = ext4_xattr_get(inode, name_index, "", value, retval);
	}
	if (retval > 0)
		acl = ext4_acl_from_disk(value, retval);
	else if (retval == -ENODATA || retval == -ENOSYS)
		acl = NULL;
	else
		acl = ERR_PTR(retval);
	kfree(value);
	return acl;
}

void sctp_generate_t3_rtx_event(unsigned long peer)
{
 	int error;
 	struct sctp_transport *transport = (struct sctp_transport *) peer;
 	struct sctp_association *asoc = transport->asoc;
	struct net *net = sock_net(asoc->base.sk);
	bh_lock_sock(asoc->base.sk);
	if (sock_owned_by_user(asoc->base.sk)) {
 		pr_debug("%s: sock is busy\n", __func__);
		if (!mod_timer(&transport->T3_rtx_timer, jiffies + (HZ/20)))
			sctp_transport_hold(transport);
		goto out_unlock;
	}
	if (transport->dead)
		goto out_unlock;
	error = sctp_do_sm(net, SCTP_EVENT_T_TIMEOUT,
			   SCTP_ST_TIMEOUT(SCTP_EVENT_TIMEOUT_T3_RTX),
			   asoc->state,
			   asoc->ep, asoc,
 			   transport, GFP_ATOMIC);
 	if (error)
		asoc->base.sk->sk_err = -error;
 out_unlock:
	bh_unlock_sock(asoc->base.sk);
 	sctp_transport_put(transport);
 }

crm_recv_remote_msg(void *session, gboolean encrypted)
 {
    char *reply = NULL;
     xmlNode *xml = NULL;
     if (encrypted) {
 #ifdef HAVE_GNUTLS_GNUTLS_H
        reply = cib_recv_tls(session);
 #else
         CRM_ASSERT(encrypted == FALSE);
 #endif
     } else {
        reply = cib_recv_plaintext(GPOINTER_TO_INT(session));
     }
     if (reply == NULL || strlen(reply) == 0) {
         crm_trace("Empty reply");
    } else {
        xml = string2xml(reply);
        if (xml == NULL) {
            crm_err("Couldn't parse: '%.120s'", reply);
         }
     }
    free(reply);
    return xml;
 }

void ChromotingHost::OnClientDisconnected(ClientSession* client) {
  DCHECK_EQ(context_->main_message_loop(), MessageLoop::current());
  scoped_refptr<ClientSession> client_ref = client;
  ClientList::iterator it;
  for (it = clients_.begin(); it != clients_.end(); ++it) {
    if (it->get() == client)
      break;
  }
  clients_.erase(it);
  if (recorder_.get()) {
    recorder_->RemoveConnection(client->connection());
  }
  for (StatusObserverList::iterator it = status_observers_.begin();
       it != status_observers_.end(); ++it) {
    (*it)->OnClientDisconnected(client->client_jid());
  }
  if (AuthenticatedClientsCount() == 0) {
    if (recorder_.get()) {
      StopScreenRecorder();
    }
    EnableCurtainMode(false);
    desktop_environment_->OnLastDisconnect();
  }
}

dtls1_process_record(SSL *s)
{
	int i,al;
	int enc_err;
	SSL_SESSION *sess;
	SSL3_RECORD *rr;
	unsigned int mac_size;
	unsigned char md[EVP_MAX_MD_SIZE];
	rr= &(s->s3->rrec);
	sess = s->session;
	rr->input= &(s->packet[DTLS1_RT_HEADER_LENGTH]);
	if (rr->length > SSL3_RT_MAX_ENCRYPTED_LENGTH)
		{
		al=SSL_AD_RECORD_OVERFLOW;
		SSLerr(SSL_F_DTLS1_PROCESS_RECORD,SSL_R_ENCRYPTED_LENGTH_TOO_LONG);
		goto f_err;
		}
	rr->data=rr->input;
	rr->orig_len=rr->length;
	enc_err = s->method->ssl3_enc->enc(s,0);
	if (enc_err == 0)
		{
		rr->length = 0;
		s->packet_length = 0;
		goto err;
		}
#ifdef TLS_DEBUG
printf("dec %d\n",rr->length);
{ unsigned int z; for (z=0; z<rr->length; z++) printf("%02X%c",rr->data[z],((z+1)%16)?' ':'\n'); }
printf("\n");
#endif
	if ((sess != NULL) &&
	    (s->enc_read_ctx != NULL) &&
	    (EVP_MD_CTX_md(s->read_hash) != NULL))
		{
		unsigned char *mac = NULL;
		unsigned char mac_tmp[EVP_MAX_MD_SIZE];
		mac_size=EVP_MD_CTX_size(s->read_hash);
		OPENSSL_assert(mac_size <= EVP_MAX_MD_SIZE);
		if (rr->orig_len < mac_size ||
		    (EVP_CIPHER_CTX_mode(s->enc_read_ctx) == EVP_CIPH_CBC_MODE &&
		     rr->orig_len < mac_size+1))
			{
			al=SSL_AD_DECODE_ERROR;
			SSLerr(SSL_F_DTLS1_PROCESS_RECORD,SSL_R_LENGTH_TOO_SHORT);
			goto f_err;
			}
		if (EVP_CIPHER_CTX_mode(s->enc_read_ctx) == EVP_CIPH_CBC_MODE)
			{
			mac = mac_tmp;
			ssl3_cbc_copy_mac(mac_tmp, rr, mac_size);
			rr->length -= mac_size;
			}
		else
			{
			rr->length -= mac_size;
			mac = &rr->data[rr->length];
			}
		i=s->method->ssl3_enc->mac(s,md,0 /* not send */);
		if (i < 0 || mac == NULL || CRYPTO_memcmp(md, mac, (size_t)mac_size) != 0)
			enc_err = -1;
		if (rr->length > SSL3_RT_MAX_COMPRESSED_LENGTH+mac_size)
			enc_err = -1;
		}
	if (enc_err < 0)
		{
		rr->length = 0;
		s->packet_length = 0;
		goto err;
		}
	if (s->expand != NULL)
		{
		if (rr->length > SSL3_RT_MAX_COMPRESSED_LENGTH)
			{
			al=SSL_AD_RECORD_OVERFLOW;
			SSLerr(SSL_F_DTLS1_PROCESS_RECORD,SSL_R_COMPRESSED_LENGTH_TOO_LONG);
			goto f_err;
			}
		if (!ssl3_do_uncompress(s))
			{
			al=SSL_AD_DECOMPRESSION_FAILURE;
			SSLerr(SSL_F_DTLS1_PROCESS_RECORD,SSL_R_BAD_DECOMPRESSION);
			goto f_err;
			}
		}
	if (rr->length > SSL3_RT_MAX_PLAIN_LENGTH)
		{
		al=SSL_AD_RECORD_OVERFLOW;
		SSLerr(SSL_F_DTLS1_PROCESS_RECORD,SSL_R_DATA_LENGTH_TOO_LONG);
		goto f_err;
		}
	rr->off=0;
 	s->packet_length=0;
	dtls1_record_bitmap_update(s, &(s->d1->bitmap));/* Mark receipt of record. */
 	return(1);
 f_err:
	ssl3_send_alert(s,SSL3_AL_FATAL,al);
err:
	return(0);
}

