					} ;
				} ;
			break ;
		case PFLAC_PCM_DOUBLE :
			{	double *retpcm = (double*) pflac->ptr ;
				double norm = (psf->norm_double == SF_TRUE) ? 1.0 / (1 << (frame->header.bits_per_sample - 1)) : 1.0 ;
				for (i = 0 ; i < len && pflac->remain > 0 ; i++)
