{
	int rc;
	unsigned char p14[14], p16[16], p21[21];
	memset(p14, '\0', 14);
	memset(p16, '\0', 16);
	memset(p21, '\0', 21);
	memcpy(p14, passwd, 14);
	rc = E_P16(p14, p16);
