            avcParams->bDirectSpatialTemporal = OMX_FALSE;
            avcParams->nCabacInitIdc = 0;
 return OMX_ErrorNone;
 }
 default:
 return SoftVideoEncoderOMXComponent::internalGetParameter(index, params);
 }
