static int hns_nic_common_poll(struct napi_struct *napi, int budget)
{
	int clean_complete = 0;
	struct hns_nic_ring_data *ring_data =
		container_of(napi, struct hns_nic_ring_data, napi);
	struct hnae_ring *ring = ring_data->ring;
try_again:
	clean_complete += ring_data->poll_one(
				ring_data, budget - clean_complete,
				ring_data->ex_process);
	if (clean_complete < budget) {
		if (ring_data->fini_process(ring_data)) {
			napi_complete(napi);
			ring->q->handle->dev->ops->toggle_ring_irq(ring, 0);
		} else {
			goto try_again;
		}
	}
	return clean_complete;
}

write_header( FT_Error  error_code )
{
  FT_Face      face;
  const char*  basename;
  error = FTC_Manager_LookupFace( handle->cache_manager,
                                  handle->scaler.face_id, &face );
  if ( error )
    PanicZ( "can't access font file" );
  if ( !status.header )
  {
    basename = ft_basename( handle->current_font->filepathname );
     switch ( error_code )
     {
     case FT_Err_Ok:
      sprintf( status.header_buffer, "%s %s (file `%s')", face->family_name,
                face->style_name, basename );
       break;
     case FT_Err_Invalid_Pixel_Size:
      sprintf( status.header_buffer, "Invalid pixel size (file `%s')",
                basename );
       break;
     case FT_Err_Invalid_PPem:
      sprintf( status.header_buffer, "Invalid ppem value (file `%s')",
                basename );
       break;
     default:
      sprintf( status.header_buffer, "File `%s': error 0x%04x", basename,
           (FT_UShort)error_code );
       break;
     }
    status.header = status.header_buffer;
  }
  grWriteCellString( display->bitmap, 0, 0,
                     status.header, display->fore_color );
  sprintf( status.header_buffer, "at %g points, angle = %d",
           status.ptsize/64.0, status.angle );
  grWriteCellString( display->bitmap, 0, CELLSTRING_HEIGHT,
                     status.header_buffer, display->fore_color );
  grRefreshSurface( display->surface );
}

bool SharedMemory::Create(const SharedMemoryCreateOptions& options) {
  DCHECK_EQ(-1, mapped_file_);
  if (options.size == 0) return false;
  if (options.size > static_cast<size_t>(std::numeric_limits<int>::max()))
    return false;
  base::ThreadRestrictions::ScopedAllowIO allow_io;
  FILE *fp;
  bool fix_size = true;
  FilePath path;
  if (options.name == NULL || options.name->empty()) {
    DCHECK(!options.open_existing);
    fp = file_util::CreateAndOpenTemporaryShmemFile(&path, options.executable);
    if (fp) {
      if (unlink(path.value().c_str()))
        PLOG(WARNING) << "unlink";
    }
  } else {
     if (!FilePathForMemoryName(*options.name, &path))
       return false;
    fp = file_util::OpenFile(path, "w+x");
    if (fp == NULL && options.open_existing) {
      fp = file_util::OpenFile(path, "a+");
       fix_size = false;
     }
   }
   if (fp && fix_size) {
    struct stat stat;
    if (fstat(fileno(fp), &stat) != 0) {
      file_util::CloseFile(fp);
      return false;
    }
    const size_t current_size = stat.st_size;
    if (current_size != options.size) {
      if (HANDLE_EINTR(ftruncate(fileno(fp), options.size)) != 0) {
        file_util::CloseFile(fp);
        return false;
      }
    }
    requested_size_ = options.size;
  }
  if (fp == NULL) {
#if !defined(OS_MACOSX)
    PLOG(ERROR) << "Creating shared memory in " << path.value() << " failed";
    FilePath dir = path.DirName();
    if (access(dir.value().c_str(), W_OK | X_OK) < 0) {
      PLOG(ERROR) << "Unable to access(W_OK|X_OK) " << dir.value();
      if (dir.value() == "/dev/shm") {
        LOG(FATAL) << "This is frequently caused by incorrect permissions on "
                   << "/dev/shm.  Try 'sudo chmod 1777 /dev/shm' to fix.";
      }
    }
#else
    PLOG(ERROR) << "Creating shared memory in " << path.value() << " failed";
#endif
    return false;
  }
  return PrepareMapFile(fp);
}

