static void derive_permissions_locked(struct fuse* fuse, struct node *parent,
 struct node *node) {
 appid_t appid;
    node->perm = PERM_INHERIT;
    node->userid = parent->userid;
    node->uid = parent->uid;
    node->under_android = parent->under_android;
 switch (parent->perm) {
 case PERM_INHERIT:
 break;
 case PERM_PRE_ROOT:
        node->perm = PERM_ROOT;
        node->userid = strtoul(node->name, NULL, 10);
 break;
 case PERM_ROOT:
 if (!strcasecmp(node->name, "Android")) {
            node->perm = PERM_ANDROID;
            node->under_android = true;
 }
 break;
 case PERM_ANDROID:
 if (!strcasecmp(node->name, "data")) {
            node->perm = PERM_ANDROID_DATA;
 } else if (!strcasecmp(node->name, "obb")) {
            node->perm = PERM_ANDROID_OBB;
            node->graft_path = fuse->global->obb_path;
            node->graft_pathlen = strlen(fuse->global->obb_path);
 } else if (!strcasecmp(node->name, "media")) {
            node->perm = PERM_ANDROID_MEDIA;
 }
 break;
 case PERM_ANDROID_DATA:
 case PERM_ANDROID_OBB:
 case PERM_ANDROID_MEDIA:
        appid = (appid_t) (uintptr_t) hashmapGet(fuse->global->package_to_appid, node->name);
 if (appid != 0) {
            node->uid = multiuser_get_uid(parent->userid, appid);
 }
 break;
 }
}

void testRandomDecodeAfterClearFrameBufferCache(const char* gifFile)
 {
     SCOPED_TRACE(gifFile);
    RefPtr<SharedBuffer> data = readFile(gifFile);
     ASSERT_TRUE(data.get());
     Vector<unsigned> baselineHashes;
     createDecodingBaseline(data.get(), &baselineHashes);
    size_t frameCount = baselineHashes.size();
    OwnPtr<GIFImageDecoder> decoder = createDecoder();
    decoder->setData(data.get(), true);
    for (size_t clearExceptFrame = 0; clearExceptFrame < frameCount; ++clearExceptFrame) {
        decoder->clearCacheExceptFrame(clearExceptFrame);
        const size_t skippingStep = 5;
        for (size_t i = 0; i < skippingStep; ++i) {
            for (size_t j = 0; j < frameCount; j += skippingStep) {
                SCOPED_TRACE(testing::Message() << "Random i:" << i << " j:" << j);
                ImageFrame* frame = decoder->frameBufferAtIndex(j);
                EXPECT_EQ(baselineHashes[j], hashSkBitmap(frame->getSkBitmap()));
            }
        }
    }
}

int mk_vhost_fdt_worker_init()
{
    int i;
    int j;
    struct host *h;
    struct mk_list *list;
    struct mk_list *head;
    struct vhost_fdt_host *fdt;
    struct vhost_fdt_hash_table *ht;
    struct vhost_fdt_hash_chain *hc;
    if (config->fdt == MK_FALSE) {
        return -1;
    }
    pthread_mutex_lock(&mk_vhost_fdt_mutex);
    list = mk_mem_malloc_z(sizeof(struct mk_list));
    mk_list_init(list);
    mk_list_foreach(head, &config->hosts) {
        h = mk_list_entry(head, struct host, _head);
        fdt = mk_mem_malloc(sizeof(struct vhost_fdt_host));
        fdt->host = h;
        for (i = 0; i < VHOST_FDT_HASHTABLE_SIZE; i++) {
            ht = &fdt->hash_table[i];
            ht->av_slots = VHOST_FDT_HASHTABLE_CHAINS;
            for (j = 0; j < VHOST_FDT_HASHTABLE_CHAINS; j++) {
                hc = &ht->chain[j];
                hc->fd      = -1;
                hc->hash    =  0;
                hc->readers =  0;
            }
        }
        mk_list_add(&fdt->_head, list);
    }
    mk_vhost_fdt_key = list;
    pthread_mutex_unlock(&mk_vhost_fdt_mutex);
    return 0;
}

static void DBGUNDO(struct sock *sk, const char *msg)
{
	struct tcp_sock *tp = tcp_sk(sk);
	struct inet_sock *inet = inet_sk(sk);
	if (sk->sk_family == AF_INET) {
		printk(KERN_DEBUG "Undo %s %pI4/%u c%u l%u ss%u/%u p%u\n",
		       msg,
		       &inet->inet_daddr, ntohs(inet->inet_dport),
		       tp->snd_cwnd, tcp_left_out(tp),
		       tp->snd_ssthresh, tp->prior_ssthresh,
		       tp->packets_out);
